// Get form data and spam rules
const input = $('Receive Form Submission').first().json.body;
const config = $('Configure Spam Rules').first().json;

if (!input || typeof input !== 'object') {
  return [{
    json: {
      isSpam: false,
      reasons: ['No form data received'],
      formData: {}
    }
  }];
}

const honeypotField = config.honeypotFieldName;
const timestampField = config.timestampFieldName;
const emailField = config.emailFieldName;
const minTime = config.minSubmissionTimeSeconds;
const disposableDomains = config.disposableDomains || [];

const reasons = [];
let isSpam = false;

// --- Check 1: Honeypot field ---
if (input[honeypotField] !== undefined && String(input[honeypotField]).trim() !== '') {
  isSpam = true;
  reasons.push('Honeypot field was filled — likely a bot');
}

// --- Check 2: Submission timing ---
if (input[timestampField]) {
  const submittedAt = new Date(input[timestampField]);
  const now = new Date();
  const diffSeconds = (now.getTime() - submittedAt.getTime()) / 1000;

  if (diffSeconds >= 0 && diffSeconds < minTime) {
    isSpam = true;
    reasons.push(
      `Form submitted too fast (${diffSeconds.toFixed(1)}s < ${minTime}s threshold)`
    );
  }
}

// --- Check 3: Disposable email domain ---
if (input[emailField]) {
  const emailValue = String(input[emailField]).trim();
  const domain = emailValue.split('@')[1];

  if (domain) {
    const domainLower = domain.toLowerCase();
    if (disposableDomains.includes(domainLower)) {
      isSpam = true;
      reasons.push(`Disposable email domain detected: ${domainLower}`);
    }
  }
}

// --- Build clean form data (remove honeypot + timestamp fields) ---
const formData = {};
for (const [key, value] of Object.entries(input)) {
  if (key !== honeypotField && key !== timestampField) {
    formData[key] = value;
  }
}

return [{
  json: {
    isSpam,
    reasons,
    formData
  }
}];
